#include <iostream>
#include <iomanip>
using namespace std;

int main() {
    int N;
    cin >> N;

    for (int i = 0; i < N; i++) {
        // Print a leading space before each row
        cout << ' ';
        for (int j = N; j >= 1; j--) {
            int val = i * N + j;
            cout << setw(3) << val;
        }
        cout << '\n';
    }
    return 0;
}
